import static org.junit.Assert.*;

public class StepDefs {

    private ArArchiveInputStream arInputStream;
    private ArArchiveEntry currentEntry;
    private ArArchiveEntry nextEntry;
    private boolean exceptionOccurred = false;

    @Given("an AR archive file created with standard AR headers and entries")
    public void an_ar_archive_file_created_with_standard_ar_headers_and_entries() {
        // Setup method, preparing for scenarios
    }

    @Given("an AR archive {string} with a valid global header")
    public void an_ar_archive_with_a_valid_global_header(String filename) throws IOException {
        // Creating a minimal AR archive with valid header (format: "!<arch>\n")
        byte[] arHeader = "!<arch>\n".getBytes("US-ASCII");
        // Create a simple AR entry with name "test1.xml" (padded to 16 bytes with spaces)
        // Format: filename(16) + timestamp(12) + owner(6) + group(6) + mode(8) + size(10) + end(2) + content
        String entryName = "test1.xml       "; // 16 chars with padding
        String timestamp = "1234567890  "; // 12 chars
        String owner = "0     "; // 6 chars
        String group = "0     "; // 6 chars
        String mode = "100644  "; // 8 chars
        String size = "0000000013"; // 10 chars (13 bytes content)
        String entryHeader = entryName + timestamp + owner + group + mode + size + "`\n"; // end of header
        String content = "Hello, World!";
        byte[] entryBytes = entryHeader.getBytes("US-ASCII");
        byte[] contentBytes = content.getBytes("US-ASCII");

        // Combine header and entry
        byte[] fullArchive = new byte[arHeader.length + entryBytes.length + contentBytes.length];
        System.arraycopy(arHeader, 0, fullArchive, 0, arHeader.length);
        System.arraycopy(entryBytes, 0, fullArchive, arHeader.length, entryBytes.length);
        System.arraycopy(contentBytes, 0, fullArchive, arHeader.length + entryBytes.length, contentBytes.length);

        InputStream inputStream = new ByteArrayInputStream(fullArchive);
        arInputStream = new ArArchiveInputStream(inputStream);
    }

    @Given("the archive contains exactly one entry named {string} with content")
    public void the_archive_contains_exactly_one_entry_named_with_content(String entryName) throws IOException {
        // This step just confirms the assumption that there's an entry
        // The actual implementation would need to create a proper AR file with entries
    }

    @When("I attempt to read the next entry from the stream")
    public void i_attempt_to_read_the_next_entry_from_the_stream() {
        try {
            currentEntry = (ArArchiveEntry) arInputStream.getNextEntry();
        } catch (IOException e) {
            exceptionOccurred = true;
        }
    }

    @Then("the system should return the entry with name {string}")
    public void the_system_should_return_the_entry_with_name(String expectedName) {
        assertNotNull("Entry should not be null", currentEntry);
        assertEquals("Entry name should match", expectedName, currentEntry.getName());
    }

    @Then("the system should not return null immediately after reading the global header")
    public void the_system_should_not_return_null_immediately_after_reading_the_global_header() {
        assertNotNull("Entry should not be null", currentEntry);
    }

    @Then("the subsequent attempt to read an entry should return null")
    public void the_subsequent_attempt_to_read_an_entry_should_return_null() throws IOException {
        nextEntry = (ArArchiveEntry) arInputStream.getNextEntry();
        assertNull("Next entry should be null", nextEntry);
    }

    @Given("the last entry of the archive has been read")
    public void the_last_entry_of_the_archive_has_been_read() throws IOException {
        // This simulates that we've already read the last entry
        // For our test, we'll just close the stream
    }

    @When("I attempt to read the next entry")
    public void i_attempt_to_read_the_next_entry() {
        try {
            nextEntry = null;
            if (arInputStream != null) {
                nextEntry = (ArArchiveEntry) arInputStream.getNextEntry();
            }
        } catch (IOException e) {
            exceptionOccurred = true;
        }
    }

    @Then("the system should return null indicating the end of the archive")
    public void the_system_should_return_null_indicating_the_end_of_the_archive() {
        assertNull("Should return null at end of archive", nextEntry);
    }

    @Then("the system should not throw an exception for a valid EOF")
    public void the_system_should_not_throw_an_exception_for_a_valid_eof() {
        assertFalse("Should not have thrown an exception", exceptionOccurred);
    }
}

