 *
 * @return the next AR entry.
 * @throws IOException
 *             if the entry could not be read
 */
public ArArchiveEntry getNextArEntry() throws IOException {
                // hit EOF before previous entry was complete
                // TODO: throw an exception instead?

    if (offset == 0) {
        final byte[] expected = ArArchiveEntry.HEADER.getBytes();
        final byte[] realized = new byte[expected.length];
        final int read = read(realized);
        if (read != expected.length) {
            throw new IOException("failed to read header");
        }
        for (int i = 0; i < expected.length; i++) {
            if (expected[i] != realized[i]) {
                throw new IOException("invalid header " + new String(realized));
            }
        }
    }

    // Check if we've reached the end of the stream by trying to peek ahead
    // We need at least enough bytes for the entry header (60 bytes) + trailer (2 bytes) = 62 bytes minimum
    // Actually we need to check if we can read a complete entry header

    // First, handle padding if the current offset is odd
    if (offset % 2 != 0) {
        int pad = read();
        if (pad < 0) {
            // If we can't read padding, we're at EOF
            return null;
        }
    }

    // Peek to see if we have enough bytes for an entry header
    // Read the entry header components one by one and check for EOF
    final byte[] name = new byte[16];
    final byte[] lastmodified = new byte[12];
    final byte[] userid = new byte[6];
    final byte[] groupid = new byte[6];
    final byte[] filemode = new byte[8];
    final byte[] length = new byte[10];

    // Try to read the name field
    int read = read(name);
    if (read < 0) {
        // Hit EOF before reading any bytes of the header - we're done
        return null;
    }
    if (read != 16) {
        // Partial read - we hit EOF in the middle of the header
        // For a proper implementation, this means invalid archive
        throw new IOException("Truncated entry header");
    }

    // Try to read remaining header fields
    if (read(lastmodified) != 12) {
        throw new IOException("Truncated entry header");
    }
    if (read(userid) != 6) {
        throw new IOException("Truncated entry header");
    }
    if (read(groupid) != 6) {
        throw new IOException("Truncated entry header");
    }
    if (read(filemode) != 8) {
        throw new IOException("Truncated entry header");
    }
    if (read(length) != 10) {
        throw new IOException("Truncated entry header");
    }

    // Try to read the trailer
    {
        final byte[] expected = ArArchiveEntry.TRAILER.getBytes();
        final byte[] realized = new byte[expected.length];
        final int trailerRead = read(realized);
        if (trailerRead != expected.length) {
            throw new IOException("Truncated entry header - trailer");
        }
        for (int i = 0; i < expected.length; i++) {
            if (expected[i] != realized[i]) {
                throw new IOException("invalid entry header. not read the content?");
            }
        }
    }

    return new ArArchiveEntry(new String(name).trim(),
                                      Long.parseLong(new String(length)
                                                     .trim()));
}

